[CmdletBinding()]
param([string]$ConfigPath=(Join-Path (Split-Path -Parent $PSScriptRoot) 'config\assistant-adapters.json'),[switch]$Json)
$ErrorActionPreference='Stop';$root=Split-Path -Parent $PSScriptRoot;$doc=Get-Content $ConfigPath -Raw|ConvertFrom-Json;$items=@($doc.adapters|ForEach-Object{$verified=[bool]((Test-Path (Join-Path $root $_.installer)) -and (Test-Path (Join-Path $root $_.smokeTest)));$support=if($_.status -eq 'tested' -and $verified){'supported'}elseif($_.status -eq 'tested'){'configured-not-verified'}else{'unsupported'};[pscustomobject]@{id=$_.id;installer=$_.installer;loader=$_.loader;smokeTest=$_.smokeTest;declaredStatus=$_.status;support=$support;verified=$verified;limitations='Only adapters in config/assistant-adapters.json have an installer contract. No other assistant is implied supported.'}});if($Json){$items|ConvertTo-Json -Depth 3}else{$items|Select-Object id,support,verified,installer,loader|Format-Table -AutoSize;Write-Output 'Only listed adapters have an installer contract; unlisted assistants are unsupported.'}
